vision_lesson_computation('IM-G6-U1-L6', "parallelogram_B_area", "120 square centimeters", 'Activity 6.2, Question 1', "148", figure).
vision_lesson_computation('IM-G6-U1-L6', "parallelogram_C_area", "63 square centimeters", 'Activity 6.2, Question 1', "148", figure).
vision_lesson_computation('IM-G6-U1-L6', "parallelogram_D_area", "35 square centimeters", 'Activity 6.2, Question 1', "148-149", figure).
