vision_lesson_computation('IM-G6-U1-L12', "surface_area_rectangular_prism_from_12cubes_2", "38 square units", 'Activity 12.3 Prisms Built from Cubes — ', "266", figure).
vision_lesson_computation('IM-G6-U1-L12', "surface_area_rectangular_prism_snapcubes", "62 square units", 'Activity 12.4 A Snap Cube Prism — Studen', "269", figure).
vision_lesson_boundary('IM-G6-U1-L12', "This lesson introduces surface area as the total area of all faces of a 3D shape. Students frequently miscount visible faces or omit hidden/opposite faces—especially when working from isometric sketches—and may conflate surface area with volume; repeatedly emphasize that all six faces of a rectangular prism must be counted, including those not drawn.").

vision_lesson('IM-G6-U1-L13', 6, 1, 13, "Polyhedra").
vision_lesson_goal('IM-G6-U1-L13', teacher, "Compare and contrast (orally and in writing) features of prisms and pyramids.").
vision_lesson_goal('IM-G6-U1-L13', teacher, "Comprehend and use the words 'face', 'edge', 'vertex', and 'base' to describe polyhedra (in spoken and written language).").
vision_lesson_goal('IM-G6-U1-L13', teacher, "Understand that the word 'net' refers to a two-dimensional figure that can be assembled into a polyhedron, and create a net for a given polyhedron.").
vision_lesson_goal('IM-G6-U1-L13', student, "Let's investigate polyhedra.").
vision_lesson_purpose('IM-G6-U1-L13', "In this lesson, students learn about polyhedra and their nets. They study prisms and pyramids as types of polyhedra with certain defining features. Students begin by identifying the defining characteristics of polyhedra and reviewing terminology (faces, edges, vertices). Next, they explore the defining characteristics of prisms and pyramids, considering the polygons that make up their faces and how to arrange them into nets that can be assembled into the given polyhedron. As students analyze and distinguish these figures, they practice looking for and making use of structure. An optional activity allows students to assemble a net into a polyhedron and identify the number of vertices, edges, and faces.").
vision_lesson_standard('IM-G6-U1-L13', building_on, '6.G.A.4').
vision_lesson_standard('IM-G6-U1-L13', addressing, '6.G.A.4').
vision_lesson_standard('IM-G6-U1-L13', building_toward, '6.G.A.4').
vision_lesson_computation('IM-G6-U1-L13', "match_nets_to_polyhedron", "Nets 1 and 2 can be folded into Pyramid P; Net 3 cannot", 'Activity 2 (13.2), Question 2', "281-282", figure).
vision_lesson_computation('IM-G6-U1-L13', "identify_polygon_composition", "Sample: Prism A—2 triangles and 3 rectangles; Pyramid R—1 pentagon and 5 triangles", 'Activity 2 (13.2), Question 3a', "281-282", text).
vision_lesson_computation('IM-G6-U1-L13', "count_polyhedron_vertices_edges_faces", "Sample: A—6 vertices, 9 edges, 5 faces; B—8 vertices, 12 edges, 6 faces", 'Activity 3 (13.3), Question 2', "283-284", text).
vision_lesson_computation('IM-G6-U1-L13', "classify_polyhedron_and_count_parts", "Prism; 10 faces, 24 edges, 16 vertices", 'Practice Problem 2', "289", figure).
vision_lesson_boundary('IM-G6-U1-L13', "This lesson builds the vocabulary and structural vocabulary (faces, edges, vertices) needed to reason about polyhedra, and establishes nets as the 2D representation of 3D solids. Students often struggle with counting vertices and edges accurately when assembling or analyzing polyhedra; the lesson recommends labeling parts and organizing counts by location (top, bottom, sides). The key misunderstanding students bring is that all faces of a prism must be the same shape—prisms can have rectangular faces that are not squares, as long as they have two identical parallel bases.").

vision_lesson('IM-G6-U1-L14', 6, 1, 14, "Nets and Surface Area").
vision_lesson_goal('IM-G6-U1-L14', teacher, "Match polyhedra with their nets and justify (orally) that they match.").
vision_lesson_goal('IM-G6-U1-L14', teacher, "Use a net with gridlines to calculate the surface area of a prism or pyramid and explain (in writing) the solution method.").
vision_lesson_goal('IM-G6-U1-L14', teacher, "Visualize and identify the polyhedron that can be assembled from a given net.").
vision_lesson_goal('IM-G6-U1-L14', student, "Let's use nets to find the surface area of polyhedra.").
vision_lesson_purpose('IM-G6-U1-L14', "This lesson extends students' understanding of polyhedra, their nets, and their surface area. Students begin by matching polyhedra and their nets. Then they work in groups to assemble two prisms and a pyramid from given nets and use nets to find the surface area of each polyhedron. To support students in reasoning about area, the nets are presented with a grid. As students calculate surface area and consider how to account for all the faces of a polyhedron, they have opportunities to look for and make use of structure, in both the arrangement and measurements of the polygons that compose the polyhedron (MP7).").
vision_lesson_standard('IM-G6-U1-L14', addressing, '6.G.A.4').
vision_lesson_computation('IM-G6-U1-L14', "rectangular_prism_surface_area_A", "82 square units", 'Activity 14.2, Student Response, part 3', "297", figure).
vision_lesson_computation('IM-G6-U1-L14', "square_pyramid_surface_area_B", "48 square units", 'Activity 14.2, Student Response, part 3', "297", figure).
vision_lesson_computation('IM-G6-U1-L14', "triangular_prism_surface_area_C", "48 square units", 'Activity 14.2, Student Response, part 3', "297", figure).
vision_lesson_computation('IM-G6-U1-L14', "rectangular_prism_surface_area_cooldown", "52 square units", 'Activity 14.3 (Unfolded), Student Respon', "300", figure).
vision_lesson_computation('IM-G6-U1-L14', "triangular_prism_surface_area_practice", "72 square units", 'Practice Problem 2b', "303", figure).
vision_lesson_boundary('IM-G6-U1-L14', "Students must mentally rotate a flat net into a 3D polyhedron and systematically calculate surface area. The central challenge: ensuring all faces are accounted for without double-counting or missing any. Visual confusion between prisms and pyramids occurs when students don't name the base shape; stress naming polyhedra by their base type. The lesson's strength is showing that nets make all faces visible at once, making systematic calculation possible if students organize their work carefully.").

vision_lesson('IM-G6-U1-L15', 6, 1, 15, "More Nets, More Surface Area").
vision_lesson_goal('IM-G6-U1-L15', teacher, "Draw and assemble a net for the prism or pyramid shown in a given drawing.").
vision_lesson_goal('IM-G6-U1-L15', teacher, "Interpret (using words and other representations) two-dimensional representations of prisms and pyramids.").
vision_lesson_goal('IM-G6-U1-L15', teacher, "Use a net without gridlines to calculate the surface area of a prism or pyramid and explain (in writing) the solution method.").
vision_lesson_goal('IM-G6-U1-L15', student, "Let's draw nets and find the surface area of polyhedra.").
vision_lesson_purpose('IM-G6-U1-L15', "This lesson further develops students' ability to visualize the relationship between nets and polyhedra and their capacity to reason about surface area. Previously, students identified polygons that make up the faces of a polyhedron and arranged them into a net. They also assembled given nets into polyhedra. In this lesson, students reason about the nets of polyhedra with less scaffolding. They practice mentally unfolding three-dimensional shapes, drawing two-dimensional nets, and using nets to calculate surface area. As students coordinate edge lengths and arrangements of polygons in drawings of three-dimensional figures to those in the corresponding nets, they practice reasoning concretely and abstractly.").
