vision_lesson('IM-G6-U5-L5', 6, 5, 5, "IM-G6-U5-L5: Using Fractions to Multiply Decimals").
vision_lesson_goal('IM-G6-U5-L5', teacher, "Identify and generate multiplication expressions that use whole numbers and decimals such as 0.1, 0.01, and 0.001 to represent the product of two decimals, and find its value.").
