vision_lesson_computation('IM-G6-U8-L2', "find_pencil_length_range", "longest pencil minus shortest pencil in class data; specific value varies by class measurements", 'Activity 2.1, question 2', "70", text).
vision_lesson_computation('IM-G6-U8-L2', "find_mode_pencil_length", "most frequently occurring pencil length; may be no clear mode or multiple modes depending on distribution", 'Activity 2.1, question 3', "70", text).
vision_lesson_computation('IM-G6-U8-L2', "find_difference_mode_to_minimum_pencil", "most common pencil length minus shortest pencil length; value varies based on class data", 'Activity 2.1, question 4', "70", text).
vision_lesson_boundary('IM-G6-U8-L2', "A statistical question requires data collection and expects variability in responses—where different answers are likely. Students often mistake 'needing analysis' for 'being statistical,' missing that variability (not all answers the same) is the defining feature that determines whether a question is statistical.").

vision_lesson('IM-G6-U8-L3', 6, 8, 3, "Representing Data Graphically").
vision_lesson_goal('IM-G6-U8-L3', teacher, "Comprehend that the word frequency refers to the number of times a particular value occurs in a data set.").
vision_lesson_goal('IM-G6-U8-L3', teacher, "Create and interpret a dot plot to answer statistical questions about a numerical data set.").
vision_lesson_goal('IM-G6-U8-L3', teacher, "Justify (in writing) whether a dot plot is an appropriate way to display a given data set, paying attention to whether the data set is numerical or categorical.").
vision_lesson_goal('IM-G6-U8-L3', student, "Let's represent data with dot plots and bar graphs.").
vision_lesson_purpose('IM-G6-U8-L3', "Students represent distributions of numerical data with dot plots after organizing them into frequency tables. Using graphical representations of distributions, they develop spatial understanding of distributions in preparation for understanding center and spread in future lessons. Students make use of the structure of dot plots to describe distributions and draw conclusions about the data.").
vision_lesson_standard('IM-G6-U8-L3', building_on, '3.MD.B.3').
vision_lesson_standard('IM-G6-U8-L3', addressing, '6.SP.A.1').
vision_lesson_standard('IM-G6-U8-L3', addressing, '6.SP.B.4').
