vision_lesson_boundary('IM-G6-U9-L9', "This lesson teaches gerrymandering by showing that even with the same population distribution, different district boundaries produce different election outcomes. Students often assume that total vote counts determine winners, not realizing that representation by district matters; they may also struggle to understand what constitutes a fair map when constraints like connectedness and equal area are involved.").

vision_lesson('IM-G6-U9-L10', 6, 9, 10, "Rectangle Madness").
vision_lesson_goal('IM-G6-U9-L10', teacher, "Coordinate diagrams and expressions involving equivalent fractions.").
vision_lesson_goal('IM-G6-U9-L10', teacher, "Interpret and create diagrams involving a rectangle decomposed into squares.").
