vision_lesson_goal('IM-G7-U1-L6', teacher, "Generalize (orally) that the area of a scaled copy is the product of the area of the original figure and the \"square\" of the scale factor.").
vision_lesson_goal('IM-G7-U1-L6', teacher, "Recognize that a two-dimensional attribute, like area, scales at a different rate than do one-dimensional attributes, like length and distance.").
vision_lesson_goal('IM-G7-U1-L6', student, "Let's build scaled shapes and investigate their areas.").
