vision_lesson('IM-G7-U3-L7', 7, 3, 7, "Exploring the Area of a Circle").
vision_lesson_goal('IM-G7-U3-L7', teacher, "Solve problems involving the area of a circle.").
vision_lesson_goal('IM-G7-U3-L7', student, "Not stated on this page (assessment/problem section only)").
vision_lesson_purpose('IM-G7-U3-L7', "Not provided on this page (shows assessment task, not lesson purpose statement)").
