vision_lesson('IM-G7-U4-L8', 7, 4, 8, "Percent Increase and Decrease with Equations").
vision_lesson_goal('IM-G7-U4-L8', teacher, "Explain (orally and in writing) how to calculate the original amount given the new amount and a percentage of increase or decrease.").
