vision_lesson_goal('IM-G7-U7-L12', teacher, "Verify linear equation solutions and identify procedural errors through substitution").
vision_lesson_purpose('IM-G7-U7-L12', "Students practice with angle relationships at intersecting lines, equivalent expressions for percent change, and linear equation solving with error detection and verification.").
