vision_lesson('IM-G7-U8-L11', 7, 8, 11, "Proportional Relationships: Area and Perimeter of Squares").
vision_lesson_goal('IM-G7-U8-L11', teacher, "Understand that not all relationships between geometric quantities are proportional").
vision_lesson_goal('IM-G7-U8-L11', teacher, "Recognize that a proportional relationship must pass through the origin on a coordinate graph").
vision_lesson_goal('IM-G7-U8-L11', teacher, "Connect algebraic and graphical representations of relationships").
vision_lesson_goal('IM-G7-U8-L11', student, "Investigate whether the relationship between the area and perimeter of a square is proportional, and explain your reasoning using a coordinate graph.").
vision_lesson_purpose('IM-G7-U8-L11', "This practice problem asks students to examine the relationship between area and perimeter of a square by plotting ordered pairs on a coordinate graph and determining whether the relationship is proportional. Students learn that while both area and perimeter relate to the side length of a square, their relationship to each other (area vs. perimeter) is non-linear and therefore not proportional.").
vision_lesson_standard('IM-G7-U8-L11', building_on, '6.RP.A.2').
vision_lesson_standard('IM-G7-U8-L11', building_on, '6.G.A.1').
