vision_lesson_boundary('IM-G8-U1-L11', "Congruence rests on rigid transformations, not visual resemblance or measurement matching alone. Students routinely conflate \"same area and perimeter\" with \"congruent,\" failing to see that rectangles with identical perimeters can have completely different side pairings (a 2×5 and 3×4 rectangle both have perimeter 14 but are not congruent).").

vision_lesson('IM-G8-U1-L12', 8, 1, 12, "Congruent Polygons").
vision_lesson_goal('IM-G8-U1-L12', teacher, "Critique arguments (orally) that two figures with congruent corresponding sides may be non-congruent figures.").
vision_lesson_goal('IM-G8-U1-L12', teacher, "Justify (orally and in writing) that two polygons on a grid are congruent using the definition of 'congruence' in terms of rigid transformations.").
vision_lesson_goal('IM-G8-U1-L12', student, "Let's decide if two figures are congruent.").
vision_lesson_purpose('IM-G8-U1-L12', "In this lesson, students find rigid transformations that show two figures are congruent and consider why two figures are not congruent. As students compare features of two shapes on a coordinate plane, they observe that having corresponding equal lengths is not enough to determine that two figures are congruent. Students use differences in features, such as angle measures, side lengths, perimeters, or the order of congruent sides, to construct arguments that two figures are not congruent. Students also use the structure of the coordinate plane to compare features of two figures and identify rigid transformations precisely.").
vision_lesson_standard('IM-G8-U1-L12', addressing, '8.G.A.2').
vision_lesson_computation('IM-G8-U1-L12', "find_polygon_side_lengths", "AB = 2.2, BC = 1.4, CD = 3.2, DE = 4.1, EA = 2.8", 'Practice Problems, Problem 1b', "256", figure).
