vision_lesson('IM-G8-U6-L1', 8, 6, 1, "Organizing Data").
vision_lesson_goal('IM-G8-U6-L1', teacher, "Comprehend that a 'scatter plot' represents data with two variables and does not represent a function.").
vision_lesson_goal('IM-G8-U6-L1', teacher, "Coordinate (orally and in writing) representations of data in scatter plots and tables.").
vision_lesson_goal('IM-G8-U6-L1', teacher, "Describe (orally and in writing) patterns in representations of data in scatter plots and tables, and use these representations to make predictions.").
vision_lesson_purpose('IM-G8-U6-L1', "In this lesson, students are given data from 2 variables in a table and asked to consider ways to organize it to look for any patterns. They are shown that one way to organize the data is to visualize it graphically using scatter plots. Students must reason abstractly and quantitatively (MP2) to match data to given scatter plots and use the structure of the scatter plot (MP7) to label the axes.").
vision_lesson_standard('IM-G8-U6-L1', addressing, '8.SP.A.1').
vision_lesson_standard('IM-G8-U6-L1', building_toward, '8.SP.A').
