vision_lesson_boundary('IM-G8-U6-L3', "This lesson hinges on students learning to read scatter plots at two levels: interpreting individual points as pairs of measurements (the \"zoom in\") and recognizing that patterns across points suggest population-level trends (the \"zoom out\"). The central difficulty is that a trend line is a statement about the group, not a guarantee for any individual—students often overextend trends, extrapolating beyond the data range or using trends to make predictions when context (like 60°C temperature) makes them nonsensical. The lesson does no arithmetic; all work is visual/interpretive, so it demands c").

vision_lesson('IM-G8-U6-L4', 8, 6, 4, "Fitting a Line to Data").
vision_lesson_goal('IM-G8-U6-L4', teacher, "Compare and contrast values in a data set with predictions made using a given line").
vision_lesson_goal('IM-G8-U6-L4', teacher, "Comprehend that a linear model can be used to predict values not given in the data").
vision_lesson_goal('IM-G8-U6-L4', teacher, "Identify obvious outliers on a scatter plot").
vision_lesson_goal('IM-G8-U6-L4', student, "Let's look at the scatter plots as a whole.").
vision_lesson_purpose('IM-G8-U6-L4', "To develop student understanding that linear models can represent relationships in bivariate data and be used to make predictions about unmeasured values and identify points that do not fit the overall pattern.").
vision_lesson_standard('IM-G8-U6-L4', addressing, '8.SP.A.1').
vision_lesson_standard('IM-G8-U6-L4', addressing, '8.SP.A.2').
