vision_lesson_computation('IM-G8-U6-L10', "determine_association_erasers", "Positive association: yellow and green erasers are more likely to be flawed than red and blue erasers", 'Activity 10.3, Question 2', "193", text).
vision_lesson_boundary('IM-G8-U6-L10', "This lesson asks students to distinguish relative frequency from absolute frequency when analyzing categorical data—a crucial distinction that many students miss when first constructing and reading segmented bar graphs. The core challenge is not the arithmetic (simple percentages and subtraction) but learning to use relative frequencies to compare groups of different sizes and recognize when differences in proportions signal a statistical association. Students commonly graph raw frequencies instead of relative frequencies, or create stacked bars without properly scaling to percentages.").

vision_lesson('IM-G8-U6-L11', 8, 6, 11, "Gone in 30 Seconds").
vision_lesson_goal('IM-G8-U6-L11', teacher, "Compare and contrast (orally) representations of bivariate data, including scatter plots, two-way tables, segmented bar graphs, and relative frequency tables.").
vision_lesson_goal('IM-G8-U6-L11', teacher, "Describe (orally and in writing) associations in bivariate data using different representations of the same data.").
vision_lesson_goal('IM-G8-U6-L11', student, "Let's gather and analyze some timing data.").
vision_lesson_purpose('IM-G8-U6-L11', "In this optional culminating lesson, students collect, represent, and analyze quantitative bivariate data. Then they group the quantitative data to create two categories, and look for evidence of an association in the resulting categorical data. This lesson allows students the opportunity to carry out the entire process of data analysis beginning with data collections and ending with an analysis of graphical representations to determine whether there is an association between two variables in the data (MP1). Students attempt to describe their reaction times by using the various techniques from the unit to model (MP4) their data.").
vision_lesson_standard('IM-G8-U6-L11', addressing, '8.SP.A').
vision_lesson_computation('IM-G8-U6-L11', "bivariate_scatter_plot_construction", "Scatter plot showing approximately 20 data points representing (Time 1, Time 2) pairs from entire class; x-axis and y-axis both range approximately 0–50 seconds; data cluster tightly around the point (30, 30); no clear positive or negative association; no outliers identified", 'Activity 11.1, Task 5', "203-204", figure).
vision_lesson_computation('IM-G8-U6-L11', "categorical_bivariate_frequency_table_completion", "Two-way contingency table with Time 1 categories (< 30 sec, = 30 sec, > 30 sec) as rows and Time 2 categories (< 30 sec, = 30 sec, > 30 sec) as columns; sample cell values in rows: (2, 1, 9); (1, 0, 1); (2, 1, 9)", 'Activity 11.1, Task 6', "203-205", figure).
vision_lesson_boundary('IM-G8-U6-L11', "Students conduct the full data analysis cycle with real reaction-time measurements, contrasting how numerical scatter plots and categorical two-way tables reveal association differently. A common error is interpreting tight clustering around a reference point (30 seconds) as evidence of association; they must learn to read two-way table relative frequencies to confirm that similar distributions across categories mean no association.").

vision_lesson('IM-G8-U6-L14', 8, 6, 14, "Grade 8 Unit 6 Practice Problems — Page 136").
vision_lesson_goal('IM-G8-U6-L14', student, "Solve systems of linear equations.").
vision_lesson_purpose('IM-G8-U6-L14', "Not available on page 136 (practice problem page only).").
